// Recibir output del sub-workflow (Lector de Pedidos)
const input = $input.all();

let listaPedidos = [];

if (input.length === 1 && input[0].json.listaPedidos) {
  listaPedidos = input[0].json.listaPedidos;
} else if (input.length > 1) {
  listaPedidos = input.map(i => i.json);
}

console.log('[Seguimiento] Total pedidos recibidos del Lector:', listaPedidos.length);

// Filtrar: estado vacío O "Pendiente"
const pendientes = listaPedidos.filter(p => {
  const est = (p.estado || '').trim();
  return est === '' || est === 'Pendiente';
});

console.log('[Seguimiento] Pedidos pendientes/sin estado:', pendientes.length);

// Si no hay pendientes, retornar array vacío — n8n detiene el flujo aquí
if (pendientes.length === 0) {
  console.log('[Seguimiento] Sin pedidos pendientes. Workflow se detiene.');
  return [];
}

// Agrupar por proveedor
const grupos = {};
for (const p of pendientes) {
  const prov = (p.proveedor || 'SIN PROVEEDOR').trim();
  if (!grupos[prov]) grupos[prov] = [];
  grupos[prov].push(p);
}

console.log('[Seguimiento] Proveedores con pedidos pendientes:', Object.keys(grupos).length);

// Generar un item por cada proveedor
const resultado = [];
for (const [proveedor, pedidos] of Object.entries(grupos)) {
  if (pedidos.length === 0) continue;
  resultado.push({
    json: {
      proveedor,
      cantidadPedidos: pedidos.length,
      pedidos
    }
  });
}

return resultado;

const CORREOS_PROVEEDORES = {
  'PRACARGO': {
    to: 'despachos@pracargo.com',
    cc: ''
  },
  'ENTRAPETROL': {
    to: 'gerencia@stentrapetrol.com',
    cc: 'trafico@stentrapetrol.com'
  },
  'TRASAMER S.A.S': {
    to: 'trasamergerencia@gmail.com',
    cc: ''
  },
  'LOGISTICA Y SERVICIOS JR S.A.S': {
    to: 'comercial1jrlogistic@gmail.com',
    cc: 'comercial1@logisticjr.com'
  },
  'TRANSPORTE NUEVA COLOMBIA': {
    to: 'despachoscali2@transnuevacolombia.com',
    cc: 'cristian.gomez@transnuevacolombia.com'
  }
};

const CC_INTERNO = 'bernardojaristizabal@gmail.com, proyectos@avgust.com.co';

const items = $input.all();
const results = [];

for (const item of items) {
  const proveedor = item.json.proveedor;
  const pedidos = item.json.pedidos;
  const config = CORREOS_PROVEEDORES[proveedor];

  // Determinar destinatario y CC
  let sendTo, ccList, asunto;

  if (config) {
    sendTo = config.to;
    const ccParts = [CC_INTERNO];
    if (config.cc && config.cc.trim() !== '') {
      ccParts.push(config.cc);
    }
    ccList = ccParts.join(', ');
    asunto = `[LogxIA] Pedidos pendientes de actualización - ${proveedor}`;
  } else {
    // Proveedor no configurado: solo a internos
    sendTo = 'bernardojaristizabal@gmail.com';
    ccList = 'proyectos@avgust.com.co';
    asunto = `[SIN CORREO CONFIGURADO - ${proveedor}]`;
  }

  const filas = pedidos.map(p => {
    const estado = (p.estado || '').trim() === '' ? 'Sin reporte' : p.estado;
    return `<tr>
      <td style="border:1px solid #ddd;padding:8px;">${p.consecutivo || '-'}</td>
      <td style="border:1px solid #ddd;padding:8px;">${p.cliente || '-'}</td>
      <td style="border:1px solid #ddd;padding:8px;">${p.origen || '-'}</td>
      <td style="border:1px solid #ddd;padding:8px;">${p.destino || '-'}</td>
      <td style="border:1px solid #ddd;padding:8px;">${p.fechaCargue || '-'}</td>
      <td style="border:1px solid #ddd;padding:8px;">${estado}</td>
    </tr>`;
  }).join('\n');

  const html = `<p>Estimado equipo de <strong>${proveedor}</strong>,</p>
<p>Le recordamos que los siguientes pedidos requieren actualización de estado:</p>
<table style="border-collapse:collapse;width:100%;font-family:Arial,sans-serif;font-size:14px;">
  <thead>
    <tr style="background-color:#f2f2f2;">
      <th style="border:1px solid #ddd;padding:8px;text-align:left;">Consecutivo</th>
      <th style="border:1px solid #ddd;padding:8px;text-align:left;">Cliente</th>
      <th style="border:1px solid #ddd;padding:8px;text-align:left;">Origen</th>
      <th style="border:1px solid #ddd;padding:8px;text-align:left;">Destino</th>
      <th style="border:1px solid #ddd;padding:8px;text-align:left;">Fecha Cargue</th>
      <th style="border:1px solid #ddd;padding:8px;text-align:left;">Estado actual</th>
    </tr>
  </thead>
  <tbody>
    ${filas}
  </tbody>
</table>
<p>Por favor actualice el estado de cada pedido a través de la aplicación <strong>"Donde Está Mi Pedido"</strong> o responda este correo con las novedades.</p>
<p>Gracias,<br/>
<strong>LogxIA — Agente de Seguimiento Logístico</strong><br/>
<em>by Logxie Connect</em></p>`;

  console.log(`[Generar Email] ${proveedor} -> TO: ${sendTo} | CC: ${ccList}`);

  results.push({
    json: {
      proveedor,
      cantidadPedidos: pedidos.length,
      asunto,
      cuerpoHtml: html,
      sendTo,
      ccList
    }
  });
}

console.log('[Generar Email] Emails generados:', results.length);
return results;
